def do_custom_validation(model, layer):
    if model == "bert" and (layer == "linear_mx_default_4" or layer == "gelu"):
        return verify_bert_gelu()
    elif model == "llama_prefill" and (layer == "linear_mx_default_4" or layer == "silu"):
        return verify_llama_prefill_silu()
    elif model == "bert" and layer == "tanh":
        return verify_bert_tanh()
    elif model == "fakegemm" and layer == "linear_default_1":
        return verify_fakegemm_linear()
    elif model == "resnet18" and layer == "submodule":
        return verify_resnet18_submodule()
    else:
        raise NotImplementedError(f"No custom validation script for model {model} layer {layer}")


def read_tensor(filename, tensor_shape):
    with open(filename, 'rb') as f:
        file_content = f.read()

    num_elements = len(file_content) // struct.calcsize('f')
    print(f"INFO: Read {num_elements} elements from binary file {filename}")
    unpacked_data = struct.unpack(f'{num_elements}f', file_content)

    tensor = torch.tensor(unpacked_data).reshape(tensor_shape)
    return tensor

def get_scale_from_bin(filename):
    with open(filename, 'rb') as f:
        file_content = f.read()

        num_elements = len(file_content) // struct.calcsize('f')
        print(f"INFO: Read {num_elements} elements from binary file {filename}")
        unpacked_data = struct.unpack(f'{num_elements}f', file_content)

        tensor = torch.tensor(unpacked_data).reshape(1,)
        return tensor[0].item()

def float_to_e8m0(x):
    # Assume input is a float32 tensor
    x = x.cpu().numpy().astype(np.float32)
    bits = np.frombuffer(x.tobytes(), dtype=np.uint32)
    e8m0 = ((bits >> 23) & 0xFF)  # extract exponent only
    return e8m0


def float32_to_bfloat16_bits(x):
    # Step 1: Move to CPU and convert to NumPy float32
    np_fp32 = x.cpu().numpy().astype(np.float32)

    # Step 2: View as uint32
    np_uint32 = np_fp32.view(np.uint32)

    # Step 3: Extract top 16 bits (bfloat16 format)
    np_bf16_uint16 = (np_uint32 >> 16).astype(np.uint16)

    return np_bf16_uint16


def write_list_to_hex(list, filename, start_addr=0, add_metadata=True, hex_width=4):
    #Write the entire tensor in hex format to a new file
    with open(filename, 'w') as output_file:
            if add_metadata:
                output_file.write(f"TENSOR_EXISTS: 1\n")
                output_file.write(f"SIZE: {len(list)}\n")
                output_file.write(f"START_ADDR: {start_addr}\n")
            for idx in range(len(list)):
                value = list[idx]
                if hex_width == 2:
                    output_file.write(str(f"{value:02x}"))
                    if idx != len(list) - 1:
                        output_file.write("\n")
                elif hex_width == 4:
                    output_file.write(str(f"{value:04x}"))
                    if idx != len(list) - 1:
                        output_file.write("\n")
                else:
                    raise ValueError(f"Unsupported hex width {hex_width} for writing hex file.")

